import { Schema, model, Document } from 'mongoose';

/**
 * Interface representing a Group in the system.
 */
export interface IGroup extends Document {
    id: string;
    name: string;
    description: string;
    adminId: string; // User ID of the creator
    members: string[]; // List of User IDs
    telegramChatId?: string; // ID of the linked Telegram chat
    createdAt: Date;
}

// Define the Group schema
const GroupSchema = new Schema<IGroup>({
    name: { type: String, required: true },
    description: { type: String },
    adminId: { type: String, required: true },
    members: { type: [String], default: [] },
    telegramChatId: { type: String },
    createdAt: { type: Date, default: Date.now }
});

// Create the Group model
const Group = model<IGroup>('Group', GroupSchema);
export default Group;

import { Schema, model, Document } from 'mongoose';

/**
 * Interface representing a Task in the system, including recurring ones.
 */
export interface ITask extends Document {
    id: string;
    groupId: string;
    title: string;
    description: string;
    assignees: string[]; // List of User IDs involved
    rotationIndex: number; // Index of the current responsible person
    unavailableMembers: string[]; // List of temporarily unavailable User IDs
    recurrence: {
        type: 'daily' | 'weekly' | 'custom';
        daysOfWeek?: number[]; // [1, 3, 5] means Mon, Wed, Fri
        time: string; // Time in "HH:mm" format (24h)
    };
    status: 'active' | 'paused';
}

// Define the Task schema
const TaskSchema = new Schema<ITask>({
    groupId: { type: String, required: true },
    title: { type: String, required: true },
    description: { type: String },
    assignees: { type: [String], required: true },
    rotationIndex: { type: Number, default: 0 },
    unavailableMembers: { type: [String], default: [] },
    recurrence: { 
        type: { type: String, enum: ['daily', 'weekly', 'custom'], required: true },
        daysOfWeek: { type: [Number] },
        time: { type: String, required: true }
    },
    status: { type: String, enum: ['active', 'paused'], default: 'active' }
});

// Create the Task model
const Task = model<ITask>('Task', TaskSchema);
export default Task;
